(1, '欢迎使用实践活动管理系统', '欢迎使用高校学生实践活动管理系统，请各位同学和老师积极使用。', 1, 'ALL', 'HIGH', 'PUBLISHED', '2026-02-15 02:02:04', 0, '2026-02-15 02:02:04', '2026-02-15 02:02:04'),
