(4, '新增功能上线', '系统新增了活动建议功能，同学们可以在活动详情页向老师提出建议。', 1, 'ALL', 'NORMAL', 'PUBLISHED', '2026-02-25 15:00:00', 0, '2026-02-25 15:00:00', '2026-02-25 15:00:00'),
(5, '端午节假期安排', '端午节假期期间，系统正常运行，祝大家节日快乐！', 1, 'ALL', 'LOW', 'PUBLISHED', '2026-03-01 09:00:00', 0, '2026-03-01 09:00:00', '2026-03-01 09:00:00'),
