(7, '春季实践活动开始报名', '2026年春季实践活动已经开始报名，欢迎同学们积极参加！', 1, 'ALL', 'HIGH', 'PUBLISHED', '2026-03-10 08:00:00', 0, '2026-03-10 08:00:00', '2026-03-10 08:00:00'),
(8, '学分查询功能上线', '同学们现在可以查询自己的学分明细了，快去看看吧！', 1, 'STUDENT', 'NORMAL', 'PUBLISHED', '2026-03-15 14:00:00', 0, '2026-03-15 14:00:00', '2026-03-15 14:00:00'),
